#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *h = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &h[i]);
        int *left = (int*)malloc(N * sizeof(int));
        int *right = (int*)malloc(N * sizeof(int));
        long long *water = (long long*)malloc(N * sizeof(long long));
        left[0] = h[0];
        for (int i = 1; i < N; ++i) left[i] = left[i-1] > h[i] ? left[i-1] : h[i];
        right[N-1] = h[N-1];
        for (int i = N-2; i >= 0; --i) right[i] = right[i+1] > h[i] ? right[i+1] : h[i];
        for (int i = 0; i < N; ++i) {
            int minH = left[i] < right[i] ? left[i] : right[i];
            water[i] = (minH > h[i]) ? (long long)(minH - h[i]) : 0LL;
        }
        long long maxSection = 0, cur = 0;
        for (int i = 0; i < N; ++i) {
            if (water[i] > 0) cur += water[i];
            else { if (cur > maxSection) maxSection = cur; cur = 0; }
        }
        if (cur > maxSection) maxSection = cur;
        printf("%lld\n", maxSection);
        free(h); free(left); free(right); free(water);
    }
    return 0;
}

