        for (int i = N-2; i >= 0; --i) right[i] = max(right[i+1], h[i]);
        for (int i = 0; i < N; ++i) {
            int minH = min(left[i], right[i]);
            water[i] = (minH > h[i]) ? (long long)(minH - h[i]) : 0LL;
        }
        long long maxSection = 0, cur = 0;
        for (long long w : water) {
            if (w > 0) cur += w;
            else { maxSection = max(maxSection, cur); cur = 0; }
        }
        maxSection = max(maxSection, cur);
        cout << maxSection << '\n';
    }
    return 0;
