public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int[] h = new int[N];
            StringTokenizer st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) h[i] = Integer.parseInt(st.nextToken());
            int[] left = new int[N];
            int[] right = new int[N];
            long[] water = new long[N];
            left[0] = h[0];
            for (int i = 1; i < N; i++) left[i] = Math.max(left[i-1], h[i]);
            right[N-1] = h[N-1];
            for (int i = N-2; i >= 0; i--) right[i] = Math.max(right[i+1], h[i]);
            for (int i = 0; i < N; i++) {
                int minH = Math.min(left[i], right[i]);
                water[i] = (minH > h[i]) ? (long)(minH - h[i]) : 0L;
            }
            long maxSection = 0, cur = 0;
            for (long w : water) {
                if (w > 0) cur += w;
                else { maxSection = Math.max(maxSection, cur); cur = 0; }
            }
            maxSection = Math.max(maxSection, cur);
            sb.append(maxSection).append('\n');
        }
        System.out.print(sb.toString());
    }
}

