import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        h = [int(next(it)) for _ in range(N)]
        left = [0]*N
        right = [0]*N
        left[0] = h[0]
        for i in range(1, N):
            left[i] = left[i-1] if left[i-1] > h[i] else h[i]
        right[N-1] = h[N-1]
        for i in range(N-2, -1, -1):
            right[i] = right[i+1] if right[i+1] > h[i] else h[i]
        max_section = cur = 0
        for i in range(N):
            min_h = left[i] if left[i] < right[i] else right[i]
            water = min_h - h[i] if min_h > h[i] else 0
            if water:
                cur += water
            else:
                if cur > max_section:
                    max_section = cur
                cur = 0
        if cur > max_section:
            max_section = cur
        out.append(str(max_section))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

